import{_ as s,o as n,c as l,a4 as t}from"./chunks/framework._in6GHBg.js";const u=JSON.parse('{"title":"遗传计算套路","description":"","frontmatter":{},"headers":[],"relativePath":"biology/routine-genetics.md","filePath":"biology/routine-genetics.md"}'),i={name:"biology/routine-genetics.md"};function e(p,a,r,o,h,c){return n(),l("div",null,[...a[0]||(a[0]=[t(`<h1 id="遗传计算套路" tabindex="-1">遗传计算套路 <a class="header-anchor" href="#遗传计算套路" aria-label="Permalink to &quot;遗传计算套路&quot;">​</a></h1><p><strong>判断遗传方式→确定基因型→计算概率→验证结果</strong></p><hr><h2 id="一、题型识别" tabindex="-1">一、题型识别 <a class="header-anchor" href="#一、题型识别" aria-label="Permalink to &quot;一、题型识别&quot;">​</a></h2><h3 id="特征关键词" tabindex="-1">特征关键词 <a class="header-anchor" href="#特征关键词" aria-label="Permalink to &quot;特征关键词&quot;">​</a></h3><ul><li>&quot;遗传概率&quot;</li><li>&quot;基因型&quot;</li><li>&quot;表现型&quot;</li><li>&quot;系谱图&quot;</li><li>&quot;患病概率&quot;</li></ul><h3 id="典型问法" tabindex="-1">典型问法 <a class="header-anchor" href="#典型问法" aria-label="Permalink to &quot;典型问法&quot;">​</a></h3><ul><li>求某表现型的概率</li><li>求某基因型的概率</li><li>系谱图分析</li><li>遗传病发病概率计算</li></ul><hr><h2 id="二、解题步骤" tabindex="-1">二、解题步骤 <a class="header-anchor" href="#二、解题步骤" aria-label="Permalink to &quot;二、解题步骤&quot;">​</a></h2><h3 id="类型1-分离定律计算" tabindex="-1">类型1：分离定律计算 <a class="header-anchor" href="#类型1-分离定律计算" aria-label="Permalink to &quot;类型1：分离定律计算&quot;">​</a></h3><p><strong>Step 1：判断显隐性</strong></p><ul><li>&quot;无中生有&quot;为隐性</li><li>&quot;有中生无&quot;为显性</li></ul><p><strong>Step 2：写基因型</strong></p><ul><li>显性性状：AA或Aa</li><li>隐性性状：aa</li></ul><p><strong>Step 3：计算概率</strong></p><ul><li>Aa × Aa → 3/4 A_ : 1/4 aa</li><li>Aa × aa → 1/2 Aa : 1/2 aa</li><li>Aa × AA → 1/2 AA : 1/2 Aa</li></ul><hr><h3 id="类型2-自由组合定律计算" tabindex="-1">类型2：自由组合定律计算 <a class="header-anchor" href="#类型2-自由组合定律计算" aria-label="Permalink to &quot;类型2：自由组合定律计算&quot;">​</a></h3><p><strong>方法：逐对分析，相乘</strong></p><p><strong>示例</strong>：AaBb × Aabb</p><ul><li>Aa × Aa → 3/4 A_ : 1/4 aa</li><li>Bb × bb → 1/2 Bb : 1/2 bb</li></ul><p><strong>组合</strong>：</p><ul><li>A_Bb = 3/4 × 1/2 = 3/8</li><li>A_bb = 3/4 × 1/2 = 3/8</li><li>aaBb = 1/4 × 1/2 = 1/8</li><li>aabb = 1/4 × 1/2 = 1/8</li></ul><hr><h3 id="类型3-伴性遗传计算" tabindex="-1">类型3：伴性遗传计算 <a class="header-anchor" href="#类型3-伴性遗传计算" aria-label="Permalink to &quot;类型3：伴性遗传计算&quot;">​</a></h3><p><strong>判断遗传方式</strong>：</p><ul><li>男患者多于女患者 → X隐性</li><li>女患者多于男患者 → X显性</li><li>只有男性患病 → Y遗传</li><li>男女患病比例相近 → 常染色体</li></ul><p><strong>写基因型</strong>（X隐性为例）：</p><ul><li>女性正常：XᴮXᴮ或XᴮXᵇ</li><li>女性患病：XᵇXᵇ</li><li>男性正常：XᴮY</li><li>男性患病：XᵇY</li></ul><p><strong>示例</strong>：XᵇY × XᴮXᵇ</p><ul><li>女儿：1/2 XᴮXᵇ（携带者），1/2 XᵇXᵇ（患病）</li><li>儿子：1/2 XᴮY（正常），1/2 XᵇY（患病）</li></ul><hr><h3 id="类型4-系谱图分析" tabindex="-1">类型4：系谱图分析 <a class="header-anchor" href="#类型4-系谱图分析" aria-label="Permalink to &quot;类型4：系谱图分析&quot;">​</a></h3><p><strong>Step 1：判断显隐性</strong></p><ul><li>无中生有 → 隐性</li><li>有中生无 → 显性</li></ul><p><strong>Step 2：判断染色体位置</strong></p><ul><li>是否与性别相关</li></ul><p><strong>Step 3：写基因型</strong></p><ul><li>根据表现型和亲子代关系推断</li></ul><p><strong>Step 4：计算概率</strong></p><p><strong>示例分析</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>系谱图显示：双亲正常，儿子患病</span></span>
<span class="line"><span>→ 无中生有，为隐性遗传</span></span>
<span class="line"><span>→ 若女儿患病，则父亲必患病（因为女儿一条X来自父亲）</span></span>
<span class="line"><span>→ 若父亲正常，则不是X隐性，为常染色体隐性</span></span></code></pre></div><hr><h2 id="三、特殊遗传现象" tabindex="-1">三、特殊遗传现象 <a class="header-anchor" href="#三、特殊遗传现象" aria-label="Permalink to &quot;三、特殊遗传现象&quot;">​</a></h2><h3 id="_1-致死现象" tabindex="-1">1. 致死现象 <a class="header-anchor" href="#_1-致死现象" aria-label="Permalink to &quot;1. 致死现象&quot;">​</a></h3><p><strong>类型</strong>：</p><ul><li>显性纯合致死（AA致死）</li><li>隐性纯合致死（aa致死）</li></ul><p><strong>处理</strong>：</p><ul><li>从分离比中排除致死类型</li><li>重新计算比例</li></ul><p><strong>示例</strong>：AA致死，Aa自交</p><ul><li>正常分离比：1 AA : 2 Aa : 1 aa</li><li>AA致死，存活：2 Aa : 1 aa</li><li>表现型比例：2 : 1（而非3 : 1）</li></ul><hr><h3 id="_2-从性遗传" tabindex="-1">2. 从性遗传 <a class="header-anchor" href="#_2-从性遗传" aria-label="Permalink to &quot;2. 从性遗传&quot;">​</a></h3><p><strong>概念</strong>：基因位于常染色体上，但在不同性别中表现不同</p><p><strong>示例</strong>：人类秃顶</p><ul><li>男性：Bb和bb都秃顶</li><li>女性：只有bb秃顶</li></ul><hr><h3 id="_3-限性遗传" tabindex="-1">3. 限性遗传 <a class="header-anchor" href="#_3-限性遗传" aria-label="Permalink to &quot;3. 限性遗传&quot;">​</a></h3><p><strong>概念</strong>：只在某一性别中表现的遗传</p><p><strong>示例</strong>：男性外耳道多毛症（Y连锁）</p><hr><h2 id="四、标准格式" tabindex="-1">四、标准格式 <a class="header-anchor" href="#四、标准格式" aria-label="Permalink to &quot;四、标准格式&quot;">​</a></h2><h3 id="计算题答题模板" tabindex="-1">计算题答题模板 <a class="header-anchor" href="#计算题答题模板" aria-label="Permalink to &quot;计算题答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：(1) 判断遗传方式：...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (2) 写出相关个体基因型：...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (3) 计算过程：...</span></span>
<span class="line"><span>        P(A_) = ...</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>    (4) 答：...</span></span></code></pre></div><hr><h2 id="五、典型例题" tabindex="-1">五、典型例题 <a class="header-anchor" href="#五、典型例题" aria-label="Permalink to &quot;五、典型例题&quot;">​</a></h2><h3 id="例题1-分离定律" tabindex="-1">例题1：分离定律 <a class="header-anchor" href="#例题1-分离定律" aria-label="Permalink to &quot;例题1：分离定律&quot;">​</a></h3><p><strong>题目</strong>：豌豆的黄色（Y）对绿色（y）为显性。一株黄色豌豆自交，后代出现绿色豌豆。求：</p><ul><li>(1) 该黄色豌豆的基因型</li><li>(2) 后代中黄色豌豆占多少？</li><li>(3) 后代黄色豌豆中纯合子占多少？</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：(1) 黄色豌豆自交后代出现绿色（yy），说明该黄色豌豆为杂合子</span></span>
<span class="line"><span>        基因型为Yy</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (2) Yy × Yy → 1 YY : 2 Yy : 1 yy</span></span>
<span class="line"><span>        黄色（Y_）占 3/4</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (3) 黄色豌豆中：1 YY : 2 Yy</span></span>
<span class="line"><span>        纯合子（YY）占 1/3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    答：(1) Yy；(2) 3/4；(3) 1/3。</span></span></code></pre></div><hr><h3 id="例题2-伴性遗传" tabindex="-1">例题2：伴性遗传 <a class="header-anchor" href="#例题2-伴性遗传" aria-label="Permalink to &quot;例题2：伴性遗传&quot;">​</a></h3><p><strong>题目</strong>：人类红绿色盲是X染色体隐性遗传病。一正常女性（其父为色盲）与一正常男性婚配，求：</p><ul><li>(1) 该女性的基因型</li><li>(2) 生育色盲男孩的概率</li><li>(3) 生育患病女孩的概率</li></ul><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：(1) 女性正常，其父色盲（XᵇY），则该女性必为携带者</span></span>
<span class="line"><span>        基因型为XᴮXᵇ</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (2) XᴮXᵇ × XᴮY</span></span>
<span class="line"><span>        女儿：1/2 XᴮXᴮ，1/2 XᴮXᵇ（均正常）</span></span>
<span class="line"><span>        儿子：1/2 XᴮY（正常），1/2 XᵇY（色盲）</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>        生育色盲男孩的概率 = 1/2（男孩）× 1/2（色盲）= 1/4</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (3) 患病女孩需要XᵇXᵇ，父亲为XᴮY，无法提供Xᵇ</span></span>
<span class="line"><span>        概率为0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    答：(1) XᴮXᵇ；(2) 1/4；(3) 0。</span></span></code></pre></div><hr><h3 id="例题3-系谱图分析" tabindex="-1">例题3：系谱图分析 <a class="header-anchor" href="#例题3-系谱图分析" aria-label="Permalink to &quot;例题3：系谱图分析&quot;">​</a></h3><p><strong>题目</strong>：某遗传病系谱图显示：Ⅰ代双亲正常，生育一患病儿子；Ⅱ代该患者与正常女性婚配，生育一正常女儿。 请分析该病的遗传方式，并计算相关概率。</p><p><strong>解答</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>解：(1) 判断遗传方式：</span></span>
<span class="line"><span>        双亲正常，儿子患病 → 无中生有，为隐性遗传</span></span>
<span class="line"><span>        若为伴X隐性，则患病儿子母亲必为携带者，符合</span></span>
<span class="line"><span>        但患者（男）与正常女性婚配，女儿正常，不能排除常染色体</span></span>
<span class="line"><span>        综合来看，最可能为常染色体隐性遗传</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (2) 基因型分析：</span></span>
<span class="line"><span>        Ⅰ代：Aa × Aa</span></span>
<span class="line"><span>        患者：aa</span></span>
<span class="line"><span>        正常女性：AA或Aa</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    (3) 概率计算（假设正常女性为携带者概率2/3）：</span></span>
<span class="line"><span>        aa × 2/3 Aa → 2/3 × 1/2 = 1/3 Aa（携带者）</span></span>
<span class="line"><span>        </span></span>
<span class="line"><span>    答：该病为常染色体隐性遗传。</span></span></code></pre></div><hr><h2 id="六、易错点清单" tabindex="-1">六、易错点清单 <a class="header-anchor" href="#六、易错点清单" aria-label="Permalink to &quot;六、易错点清单&quot;">​</a></h2><h3 id="审题阶段" tabindex="-1">审题阶段 <a class="header-anchor" href="#审题阶段" aria-label="Permalink to &quot;审题阶段&quot;">​</a></h3><ul><li>[ ] 是否判断了显隐性？</li><li>[ ] 是否判断了染色体位置？</li><li>[ ] 是否注意&quot;男孩患病&quot;vs&quot;患病男孩&quot;？</li></ul><h3 id="计算阶段" tabindex="-1">计算阶段 <a class="header-anchor" href="#计算阶段" aria-label="Permalink to &quot;计算阶段&quot;">​</a></h3><ul><li>[ ] 基因型书写是否正确？</li><li>[ ] 分离比是否正确？</li><li>[ ] 是否考虑了致死效应？</li></ul><h3 id="结论阶段" tabindex="-1">结论阶段 <a class="header-anchor" href="#结论阶段" aria-label="Permalink to &quot;结论阶段&quot;">​</a></h3><ul><li>[ ] 概率是否化简？</li><li>[ ] 是否带单位或说明？</li></ul><hr><h2 id="七、得分点提示" tabindex="-1">七、得分点提示 <a class="header-anchor" href="#七、得分点提示" aria-label="Permalink to &quot;七、得分点提示&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">步骤</th><th style="text-align:left;">得分点</th></tr></thead><tbody><tr><td style="text-align:center;">判断遗传方式</td><td style="text-align:left;">写出判断依据</td></tr><tr><td style="text-align:center;">写基因型</td><td style="text-align:left;">正确写出亲本基因型</td></tr><tr><td style="text-align:center;">计算</td><td style="text-align:left;">写出分离比或概率计算过程</td></tr><tr><td style="text-align:center;">结论</td><td style="text-align:left;">给出最终答案</td></tr></tbody></table><hr><p><strong>文档编号</strong>: Bio-Review-Routine-006<br><strong>版本</strong>: V1.0<br><strong>日期</strong>: 20260405</p>`,96)])])}const g=s(i,[["render",e]]);export{u as __pageData,g as default};
